def kth_ordered(words, k):
    if not words or k < 1 or k > len(words):
        return None

    # Group words by their length
    grouped_words = {}
    for word in words:
        length = len(word)
        if length not in grouped_words:
            grouped_words[length] = []
        grouped_words[length].append(word)

    sorted_words = []
    for length, group in sorted(grouped_words.items(), key=lambda x: (x[0], -ord(x[1][0]))):
        sorted_group = sorted(group, reverse=True)
        sorted_words.extend(sorted_group)

    return sorted_words[k-1]
